class Solution {
    public int numPairsDivisibleBy60(int[] time) {
        int[] remainders = new int[60];
        int count = 0;
        for (int t : time) {
            int remainder = t % 60;
            count += remainders[(60 - remainder) % 60];
            remainders[remainder]++;
        }
        return count;
    }
}
```

